class Solution {
public:
    int majorityElement(vector<int>& nums) {
        int candidate = -1; // 当前候选人
        int count = 0;      // 候选人的净票数
        for (int num : nums) {
            if (num == candidate)
                ++count;
            else if (--count < 0) { // 票数被抵消耗尽，换当前元素当候选人
                candidate = num;
                count = 1;
            }
        }
        return candidate;
    }
};
